from sympy import integer_nthroot
def A350224(n):
    c, j, n2 = 0, 1, n**n
    while j <= n:
        k = n2//j**n
        m = integer_nthroot(n2//k,n)[0]
        if m-j&1^1:
            c += k if j&1 else -k
        j = m+1
    return c # _Chai Wah Wu_, May 22 2026

